class Solution {
public:
    int maxChunksToSorted(vector<int>& nums) {
        int ans=0, end=0;
        for(int i=0;i<(int)nums.size();i++){
            end=max(end,nums[i]);
            if(end==i) ans++;
        }
        return ans;
    }
};

